[Form]
public class ETG_AgreementLineNotes extends FormRun
{
    AgreementLine   agreementLineInitRecord;
    FormRun         callerFormRun;

}

/// <summary>
///
/// </summary>
public void initValue()
{
    Args  args = new Args();
    AgreementLine  agreementLine;
    agreementLine = element.args().record();

    ETG_AgreementLineNotes.AgreementLine = agreementLine.RecId;
    ETG_AgreementLineNotes.ItemId        = agreementLine.ItemId;
    super();
}

/// <summary>
/// it will return True if Agreement having confirmations
/// </summary>
public boolean isAgreementHavingConfirmations(RefRecId  _AgreementHeader)
{
    boolean                 isAgreementHavingConfirmations;
    AgreementHeaderHistory  agreementHeaderHistory;

    select firstonly agreementHeaderHistory
        where agreementHeaderHistory.AgreementHeader == _AgreementHeader;

    isAgreementHavingConfirmations  = agreementHeaderHistory.RecId != 0;

    return  isAgreementHavingConfirmations;
}

/// <summary>
///
/// </summary>
public void init()
{
    boolean         editOrder = true;
    AgreementLine   agreementLine;

    if (element.args() && element.args().dataset() == tableNum(AgreementLine))
    {
        agreementLine = element.args().record();
        agreementLineInitRecord = element.args().record();
        callerFormRun = element.args().caller();

        editOrder = !this.isAgreementHavingConfirmations(agreementLine.agreementHeader().RecId);

        ETG_AgreementLineNotes_DS.allowCreate(editOrder);
        ETG_AgreementLineNotes_DS.allowEdit(editOrder);
        ETG_AgreementLineNotes_DS.allowDelete(editOrder);

        if(curExt() == "O001" || curExt() == "U008")
        {
            if(editOrder)
            {
                element.design(0).viewEditMode(ViewEditMode::Edit);
            }
            //else
            //{
            //    element.design(0).viewEditMode(ViewEditMode::View);
            //}
        }

        if(curExt() == "O001" || curExt() == "U008")
        {
            ChangeRequest.visible(true);
        }
        else
        {
            ChangeRequest.visible(false);
        }

        if(ETG_Parameters::find().CopyFromMasterMapping == NoYes::Yes)
        {
            CopyFromMaster.visible(true);
        }
        else
        {
            CopyFromMaster.visible(false);
        }

        if(ETG_Parameters::find().CopyContractPluses == NoYes::Yes)
        {
            CopyContract_pulses.visible(true);
        }
        else
        {
            CopyContract_pulses.visible(false);
        }

    }
    super();
}

public void clicked()
{
    str PurchaseOrSales;
    ETG_ACFNotesMappings    acfNotesMapping;
    ETG_ACFNotesMaster      acfNotesMaster;
    ETG_AgreementLineNotes  agreementLineNotesNew;
    Counter                 rowCount =0;
    ETGPlaceOfDischarge     destination;          

    super();
    if(agreementLineInitRecord)
    {
        AgreementHeader     agreementHeader = AgreementHeader::find(agreementLineInitRecord.Agreement);

        DimensionAttribute dimensionAttribute = DimensionAttribute::findByName("VERTICAL");
        DimensionAttributeValueSetItemView dimensionAttributeValueSetItemView;

        select firstonly DisplayValue from dimensionAttributeValueSetItemView
            where dimensionAttributeValueSetItemView.DimensionAttributeValueSet == agreementLineInitRecord.DefaultDimension
            && dimensionAttributeValueSetItemView.DimensionAttribute == dimensionAttribute.RecId;


        if(callerFormRun.name() == formStr(PurchAgreement))
        {

            PurchAgreementHeader        purchAH    = PurchAgreementHeader::find(agreementHeader.RecId);
            ETG_PurchaseAgreementHeader etgPurchAheader ;
            ETG_PlaceOfDischarge ETG_PlaceOfDischarge_Purch;


            select * from etgPurchAheader
                where etgPurchAheader.PurchAgreementId == purchAH.PurchNumberSequence;

            select firstonly ETG_PlaceOfDischarge_Purch 
                where ETG_PlaceOfDischarge_Purch.PlaceOfDischarge == etgPurchAheader.PortOfDischarge;

           // destination     = etgPurchAheader.PortOfDischarge;
            destination = ETG_PlaceOfDischarge_Purch.Country;
            PurchaseOrSales = "Purchase";

        }
        else if (callerFormRun.name() == formStr(SalesAgreement))
        {
            SalesAgreementHeader        salesAH = SalesAgreementHeader::find(agreementHeader.RecId);
            ETG_SalesAgreementHeader    etgSalesAH;
            ETG_PlaceOfDischarge        ETG_PlaceOfDischarge_sales;

            select * from etgSalesAH 
                where etgSalesAH.SalesAgreementId == salesAH.SalesNumberSequence;

            select firstonly ETG_PlaceOfDischarge_sales
                where ETG_PlaceOfDischarge_sales.PlaceOfDischarge == etgSalesAH.PortOfDischarge;

           // destination     = etgSalesAH.PortOfDischarge;
            destination     = ETG_PlaceOfDischarge_sales.Country;
            PurchaseOrSales = "Sales";
        }

        while select * from acfNotesMaster
            where acfNotesMaster.MainCommodity == agreementLineInitRecord.ETGMainCommodity &&
                acfNotesMaster.PurchaseorSales == PurchaseOrSales    
            join acfNotesMapping
            where acfNotesMapping.MainCommodity == agreementLineInitRecord.ETGMainCommodity &&
                    acfNotesMapping.NoteId        == acfNotesMaster.NoteId &&
                    acfNotesMapping.Destination   == destination &&
                    acfNotesMapping.Vertical      == dimensionAttributeValueSetItemView.DisplayValue
        {
            select agreementLineNotesNew
                where agreementLineNotesNew.AgreementLine == agreementLineInitRecord.RecId &&
                      agreementLineNotesNew.ItemId        == agreementLineInitRecord.ItemId&&
                      agreementLineNotesNew.EnumNotes     == acfNotesMaster.ContractNotesType;

            if(!agreementLineNotesNew)
            {
                ttsbegin;
                agreementLineNotesNew.clear();
                agreementLineNotesNew.AgreementLine = agreementLineInitRecord.RecId;
                agreementLineNotesNew.ItemId        = agreementLineInitRecord.ItemId;
                agreementLineNotesNew.Description   = acfNotesMaster.ContractNotesDescription;
                agreementLineNotesNew.EnumNotes     = acfNotesMaster.ContractNotesType;
                agreementLineNotesNew.PrintNotesInContract = NoYes::Yes;
                agreementLineNotesNew.AgreementSerialNumber  = acfNotesMapping.SerialNumber;//added new field to print notes by order
                agreementLineNotesNew.insert();
                ttscommit;
                rowCount++;
            }
        }                        
    }
    if (rowCount >0)
    {
        Info(strFmt("%1 No of records inserted into Agreement lines notes",rowCount));
    }
    else
    {   
        info("No new records found !");
    }
    ETG_AgreementLineNotes_DS.refresh();
    ETG_AgreementLineNotes_DS.research(true);

}

public void clicked()
{
    str PurchaseOrSales;
    ETG_ACFNotesMappings    acfNotesMapping;
    ETG_ACFNotesMaster      acfNotesMaster;
    ETG_AgreementLineNotes  agreementLineNotesNew;
    Counter                 rowCount =0;
    ETGPlaceOfDischarge     destination; 
    AgreementHeaderDefault    agreementHeaderDefault;

    super();
    if(agreementLineInitRecord)
    {
        AgreementHeader     agreementHeader = AgreementHeader::find(agreementLineInitRecord.Agreement);




        if(callerFormRun.name() == formStr(PurchAgreement))
        {

            PurchAgreementHeader        purchAH    = PurchAgreementHeader::find(agreementHeader.RecId);
            ETG_PurchaseAgreementHeader etgPurchAheader ;
            ETG_PlaceOfDischarge ETG_PlaceOfDischarge_Purch;


            select * from etgPurchAheader
                where etgPurchAheader.PurchAgreementId == purchAH.PurchNumberSequence;

            select firstonly ETG_PlaceOfDischarge_Purch 
                where ETG_PlaceOfDischarge_Purch.PlaceOfDischarge == etgPurchAheader.PortOfDischarge;

           // destination     = etgPurchAheader.PortOfDischarge;
            destination = ETG_PlaceOfDischarge_Purch.Country;
            PurchaseOrSales = "Purchase";

        }
        else if (callerFormRun.name() == formStr(SalesAgreement))
        {
            SalesAgreementHeader        salesAH = SalesAgreementHeader::find(agreementHeader.RecId);
            ETG_SalesAgreementHeader    etgSalesAH;
            ETG_PlaceOfDischarge        ETG_PlaceOfDischarge_sales;

            select * from etgSalesAH 
                where etgSalesAH.SalesAgreementId == salesAH.SalesNumberSequence;

            select firstonly ETG_PlaceOfDischarge_sales
                where ETG_PlaceOfDischarge_sales.PlaceOfDischarge == etgSalesAH.PortOfDischarge;

           // destination     = etgSalesAH.PortOfDischarge;
            destination     = ETG_PlaceOfDischarge_sales.Country;
            PurchaseOrSales = "Sales";
        }
        select AgreementHeaderDefault where AgreementHeaderDefault.AgreementHeader == agreementHeader.RecId;

        while select * from acfNotesMaster
            where     acfNotesMaster.PurchaseorSales == PurchaseOrSales  && 
                acfNotesMaster.DataAreaId  ==  curExt() &&
               (acfNotesMaster.DeliveryTerm == "" || acfNotesMaster.DeliveryTerm == AgreementHeaderDefault.DeliveryTerm)

        {
            select agreementLineNotesNew
                where agreementLineNotesNew.AgreementLine == agreementLineInitRecord.RecId &&
                      //agreementLineNotesNew.ItemId        == agreementLineInitRecord.ItemId&&
                      agreementLineNotesNew.EnumNotes     == acfNotesMaster.ContractNotesType;

            if(!agreementLineNotesNew)
            {
                ttsbegin;
                agreementLineNotesNew.clear();
                agreementLineNotesNew.AgreementLine = agreementLineInitRecord.RecId;
               // agreementLineNotesNew.ItemId        = agreementLineInitRecord.ItemId;
                agreementLineNotesNew.Description   = acfNotesMaster.ContractNotesDescription;
                agreementLineNotesNew.EnumNotes     = acfNotesMaster.ContractNotesType;
                agreementLineNotesNew.PrintNotesInContract = NoYes::Yes;
                //agreementLineNotesNew.AgreementSerialNumber  = acfNotesMapping.SerialNumber;//added new field to print notes by order
                agreementLineNotesNew.insert();
                ttscommit;
                rowCount++;
            }
        }                        
    }
    if (rowCount >0)
    {
        Info(strFmt("%1 No of records inserted into Agreement lines notes",rowCount));
    }
    else
    {   
        info("No new records found !");
    }
    ETG_AgreementLineNotes_DS.refresh();
    ETG_AgreementLineNotes_DS.research(true);

}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    this.formRun().design(ViewEditMode::Edit);

    ETG_AgreementLineNotes_ds.allowEdit(true);
    ETG_AgreementLineNotes_ds.allowCreate(true);
    ETG_AgreementLineNotes_ds.allowDelete(true);

    EnumNotes.allowEdit(true);
    Description.allowEdit(true);
    ETG_AgreementLineNotes_PrintNotesInContract.allowEdit(true);

}
